static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 1;

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k04630CustomTilingData tiling;
    const gert::StorageShape *storageShape = context->GetInputShape(0);
    const gert::Shape &originShape = storageShape->GetOriginShape();

    uint32_t N = static_cast<uint32_t>(originShape.GetDim(0));
    uint32_t C = static_cast<uint32_t>(originShape.GetDim(1));
    uint32_t H = static_cast<uint32_t>(originShape.GetDim(2));
    uint32_t W = static_cast<uint32_t>(originShape.GetDim(3));
    uint32_t halfC = C / 2;
    uint32_t spatialSize = H * W;
    uint32_t totalPoints = N * spatialSize;

    tiling.set_totalLength(totalPoints);
    tiling.set_inFeatures(C);
    tiling.set_halfFeatures(halfC);
    tiling.set_spatialStride(spatialSize);
    tiling.set_width(W);

    uint32_t maxTile = 1;  // process one point per tile
    uint32_t tileLen = maxTile;
    if (totalPoints < tileLen) tileLen = totalPoints;

    uint32_t numTiles = CeilDiv(totalPoints, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);
    tiling.set_blockDim(blockDim);
    tiling.set_tileLength(tileLen);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

